const POSITIVE = ["apartamento", "plaza", "agency", "agencia", "club", "booking", "tour", "models", "vacante", "hotel", "cita", "meeting"];
const NEGATIVE = ["crypto", "forex", "casino", "bank", "loan", "call center"];

const positiveHits = POSITIVE.filter(k => text.includes(k)).length;
const negativeHits = NEGATIVE.filter(k => text.includes(k)).length;

let reject = false, reason = null;

if (category === "trash") { reject = true; reason = "ai_trash"; }
else if (negativeHits >= 1 && positiveHits === 0) { reject = true; reason = "negative_signal"; }
else if (text.length < 60 && positiveHits === 0 && (item.positiveHits || 0) === 0) { reject = true; reason = "weak_lead"; } 

return { ...item, category: category, looksValuableFinal: !reject, reject_reason_final: reason, postPositiveHits: positiveHits };

const store = $getWorkflowStaticData('global');

if (!store.users) store.users = {};
if (!store.banned) store.banned = {};

const results = [];
const now = Date.now();

const BAN_TIME = 24 * 60 * 60 * 1000;
const MIN_MSGS = 5;
const MAX_BAD_RATIO = 0.7;
const WHITELIST = new Set(["346xxxxxxx", "admin_id"]);

for (const item of $input.all()) {
  const data = item.json;
  const sender = String(data.final_contact || data.sender_contact || "unknown");

  if (WHITELIST.has(sender)) {
    results.push(item);
    continue;
  }

  if (!store.users[sender]) {
    store.users[sender] = { good: 0, bad: 0, total: 0 };
  }

  if (store.banned[sender]) {
    const ban = store.banned[sender];
    if (now < ban.until) {
      data.looksValuableFinal = false;
      data.reject_reason_final = "user_auto_banned";
      results.push(item);
      continue;
    } else {
      delete store.banned[sender];
      store.users[sender] = { good: 0, bad: 0, total: 0 };
    }
  }

  const user = store.users[sender];
  user.good *= 0.95;
  user.bad *= 0.95;
  user.total = user.good + user.bad;
  user.total += 1;

  if (data.looksValuableFinal === false || data.trash === true) {
    user.bad += 1;
  } else {
    user.good += 1;
  }

  if (user.total >= MIN_MSGS) {
    const ratio = user.bad / user.total;
    if (ratio >= MAX_BAD_RATIO) {
      store.banned[sender] = {
        until: now + BAN_TIME,
        reason: "high_spam_ratio",
        stats: { ...user }
      };
      data.looksValuableFinal = false;
      data.reject_reason_final = "user_just_banned";
    }
  }

  results.push(item);
}

return results;

